BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?usecase ?ucName WHERE {
  VALUES ?container {
    <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%20Packages::Telescope::WorkPackages::Control::Alignment%20and%20Phasing%20System::Systems%20Engineering::09%20Views::TMT-APS-SE::TMT-APS%20Use%20Cases>
  }

  {
    ?container vocab:packagedElement+ ?usecase .
  }
  UNION
  {
    ?container vocab:Element_ownedElement+ ?usecase .
  }
  ?usecase rdf:type vocab:usecase .

  OPTIONAL { ?usecase vocab:NamedElement_name ?ucName . }
}
LIMIT 25

