BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?container ?containerType ?containerName ?linkedPred ?linkedObj WHERE {
  VALUES ?containerType { vocab:package vocab:view vocab:document }
  ?container rdf:type ?containerType .
  ?container vocab:NamedElement_name ?containerName .
  FILTER(CONTAINS(LCASE(STR(?containerName)), LCASE("TMT-APS Use Cases")))

  OPTIONAL {
    ?container ?linkedPred ?linkedObj .
    FILTER(STRSTARTS(STR(?linkedPred), STR(vocab:)))
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?cand ?candType ?candName WHERE {
  ?cand vocab:NamedElement_name ?candName .
  FILTER(
    CONTAINS(LCASE(STR(?candName)), LCASE("tmt-aps")) &&
    CONTAINS(LCASE(STR(?candName)), LCASE("use cases"))
  )
  OPTIONAL { ?cand rdf:type ?candType . }
}
LIMIT 25

