BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?uc ?ucName ?ucType WHERE {
  VALUES ?container {
    <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::09%2520Views::TMT-APS-SE::TMT-APS%2520Use%2520Cases>
    <http://api.koneksys.com/cameo/TMT/document/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::09%2520Views::TMT-APS-SE::TMT-APS%2520Use%2520Cases>
  }

  {
    ?container (vocab:packagedElement|vocab:Element_ownedElement)+ ?uc .
  }
  OPTIONAL { ?uc rdf:type ?ucType . }
  OPTIONAL { ?uc vocab:NamedElement_name ?ucName . }

  FILTER(
    (BOUND(?ucName) && CONTAINS(LCASE(STR(?ucName)), LCASE("use case")))
    || (BOUND(?ucType) && (STR(?ucType) = STR(vocab:UseCase) || STR(?ucType) = STR(vocab:usecase)))
  )
}
ORDER BY ?ucName
LIMIT 25
